import kotlinx.coroutines.ExperimentalCoroutinesApi
import kotlinx.coroutines.delay
import kotlinx.coroutines.flow.toList
import kotlinx.coroutines.launch
import kotlinx.coroutines.test.TestScope
import org.assertj.core.api.Assertions.assertThat
import org.junit.Before
import org.junit.Test
import org.mockito.Mock
import org.mockito.MockitoAnnotations
import org.mockito.kotlin.whenever
import org.wordpress.android.BaseUnitTest
import org.wordpress.android.ui.domains.management.newdomainsearch.NewDomainSearchViewModel.UiState
import org.wordpress.android.ui.domains.management.newdomainsearch.domainsfetcher.NewDomainsSearchRepository
import org.wordpress.android.ui.domains.management.newdomainsearch.domainsfetcher.NewDomainsSearchRepository.DomainsResult
import org.wordpress.android.ui.domains.management.newdomainsearch.domainsfetcher.ProposedDomain
import org.wordpress.android.util.analytics.AnalyticsTrackerWrapper

@ExperimentalCoroutinesApi
class NewDomainSearchViewModelRaceConditionTest : BaseUnitTest() {
    @Mock
    private lateinit var analyticsTracker: AnalyticsTrackerWrapper

    @Mock
    private lateinit var repository: NewDomainsSearchRepository

    private lateinit var viewModel: NewDomainSearchViewModel

    @Before
    fun setUp() {
        MockitoAnnotations.openMocks(this)
        viewModel = NewDomainSearchViewModel(
            mainDispatcher = testDispatcher(),
            analyticsTracker = analyticsTracker,
            newDomainsSearchRepository = repository
        )
    }

    @Test
    fun `GIVEN slow first request and fast second request WHEN searching THEN only latest result updates UI`() =
        testWithUiStates { states ->
            val firstDomains = listOf(
                ProposedDomain(
                    productId = 1,
                    domain = "oldresult.com",
                    price = "USD 100",
                    salePrice = null,
                    supportsPrivacy = true
                )
            )
            val secondDomains = listOf(
                ProposedDomain(
                    productId = 2,
                    domain = "newresult.com",
                    price = "USD 200",
                    salePrice = null,
                    supportsPrivacy = true
                )
            )

            // First request is slow (500ms delay)
            whenever(repository.searchForDomains("first")).then {
                Thread.sleep(500)
                DomainsResult.Success(firstDomains)
            }

            // Second request is fast (100ms delay)
            whenever(repository.searchForDomains("second")).then {
                Thread.sleep(100)
                DomainsResult.Success(secondDomains)
            }

            viewModel.onSearchQueryChanged("first")
            delay(300) // Wait for debounce
            viewModel.onSearchQueryChanged("second")
            advanceUntilIdle()

            // The last state should be from the second (latest) request, not the first
            val finalState = states.last()
            assertThat(finalState).isInstanceOf(UiState.PopulatedDomains::class.java)
            val populatedState = finalState as UiState.PopulatedDomains
            assertThat(populatedState.domains).isEqualTo(secondDomains)
            assertThat(populatedState.domains.first().domain).isEqualTo("newresult.com")
        }

    @Test
    fun `GIVEN multiple rapid requests WHEN searching THEN only latest request completes`() =
        testWithUiStates { states ->
            val domains1 = listOf(ProposedDomain(1, "first.com", "USD 100", null, true))
            val domains2 = listOf(ProposedDomain(2, "second.com", "USD 200", null, true))
            val domains3 = listOf(ProposedDomain(3, "third.com", "USD 300", null, true))

            // All requests have some delay to simulate network calls
            whenever(repository.searchForDomains("first")).then {
                Thread.sleep(300)
                DomainsResult.Success(domains1)
            }
            whenever(repository.searchForDomains("second")).then {
                Thread.sleep(300)
                DomainsResult.Success(domains2)
            }
            whenever(repository.searchForDomains("third")).then {
                Thread.sleep(100)
                DomainsResult.Success(domains3)
            }

            // Trigger searches with enough delay to pass debounce
            viewModel.onSearchQueryChanged("first")
            delay(260)
            viewModel.onSearchQueryChanged("second")
            delay(260)
            viewModel.onSearchQueryChanged("third")
            advanceUntilIdle()

            // Only the third (latest) request should complete
            val finalState = states.last()
            assertThat(finalState).isInstanceOf(UiState.PopulatedDomains::class.java)
            val populatedState = finalState as UiState.PopulatedDomains
            assertThat(populatedState.domains).isEqualTo(domains3)
            assertThat(populatedState.domains.first().domain).isEqualTo("third.com")
        }

    private fun testWithUiStates(block: suspend TestScope.(events: List<UiState>) -> Unit) = test {
        val uiStates = mutableListOf<UiState>()
        val job = launch { viewModel.uiStateFlow.toList(uiStates) }

        block(uiStates)

        job.cancel()
    }
}
"}

